        if ctx.supports_unicode() { "○" } else { "o" }
    }

    /// Tree branch
    pub fn tree_branch(ctx: OutputContext) -> &'static str {
        if ctx.supports_unicode() { "├" } else { "|" }
    }

    /// Tree end
